import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Agregar cuenta: OAuth y Refresh Token | Antigravity Tools","description":"Aprende las dos formas de agregar cuentas en Antigravity Tools. Mediante OAuth autoriza con un clic o manualmente con Refresh Token, admite importación por lotes, maneja fallos de callback y valida el pool de cuentas.","frontmatter":{"title":"Agregar cuenta: OAuth y Refresh Token | Antigravity Tools","sidebarTitle":"Agregar tu cuenta de Google","subtitle":"Agregar cuenta: dos vías OAuth/Refresh Token y mejores prácticas","description":"Aprende las dos formas de agregar cuentas en Antigravity Tools. Mediante OAuth autoriza con un clic o manualmente con Refresh Token, admite importación por lotes, maneja fallos de callback y valida el pool de cuentas.","tags":["Gestión de cuentas","OAuth","refresh_token","Google","Mejores prácticas"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"es/lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),c={name:"es/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function n(l,e,d,i,s,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="agregar-cuenta-dos-vias-oauth-refresh-token-y-mejores-practicas" tabindex="-1">Agregar cuenta: dos vías OAuth/Refresh Token y mejores prácticas <a class="header-anchor" href="#agregar-cuenta-dos-vias-oauth-refresh-token-y-mejores-practicas" aria-label="Permalink to &quot;Agregar cuenta: dos vías OAuth/Refresh Token y mejores prácticas&quot;">​</a></h1><p>En Antigravity Tools, &quot;agregar cuenta&quot; significa escribir el <code>refresh_token</code> de la cuenta de Google en el pool de cuentas local, para que las solicitudes de proxy inverso posteriores puedan usarlas de forma rotativa. Puedes seguir OAuth para autorizar con un clic, o copiar y pegar el <code>refresh_token</code> para agregar manualmente.</p><h2 id="que-puedes-hacer-al-finalizar" tabindex="-1">Qué puedes hacer al finalizar <a class="header-anchor" href="#que-puedes-hacer-al-finalizar" aria-label="Permalink to &quot;Qué puedes hacer al finalizar&quot;">​</a></h2><ul><li>Agregar cuentas de Google al pool de cuentas de Antigravity Tools mediante OAuth o Refresh Token</li><li>Copiar/abrir manualmente el enlace de autorización, y completar automáticamente la adición después de que el callback sea exitoso</li><li>Saber cómo manejar problemas como no obtener <code>refresh_token</code>, incapacidad de conectar a <code>localhost</code> en el callback</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><ul><li>Haces clic en &quot;Autorizar OAuth&quot; pero sigue girando, o el navegador muestra <code>localhost refused to connect</code></li><li>La autorización fue exitosa, pero muestra &quot;No se pudo obtener Refresh Token&quot;</li><li>Solo tienes <code>refresh_token</code> a mano y no sabes cómo importarlos por lotes de una vez</li></ul><h2 id="cuando-usar-este-enfoque" tabindex="-1">Cuándo usar este enfoque <a class="header-anchor" href="#cuando-usar-este-enfoque" aria-label="Permalink to &quot;Cuándo usar este enfoque&quot;">​</a></h2><ul><li>Quieres agregar cuentas de la forma más estable (priorizar OAuth)</li><li>Te importa más la portabilidad/respaldo (Refresh Token es más adecuado como &quot;activo del pool de cuentas&quot;)</li><li>Necesitas agregar muchas cuentas y quieres importar <code>refresh_token</code> por lotes (admite extracción desde texto/JSON)</li></ul><h2 id="🎒-preparativos-antes-de-comenzar" tabindex="-1">🎒 Preparativos antes de comenzar <a class="header-anchor" href="#🎒-preparativos-antes-de-comenzar" aria-label="Permalink to &quot;🎒 Preparativos antes de comenzar&quot;">​</a></h2><ul><li>Ya has instalado y puedes abrir la aplicación de escritorio de Antigravity Tools</li><li>Sabes dónde está la entrada: entra en la página <code>Accounts</code> desde la navegación izquierda (ruta en <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">Dos palabras clave en esta lección</p><p><strong>OAuth</strong>: un proceso de &quot;ir al navegador para iniciar sesión y autorizar&quot;. Antigravity Tools iniciará temporalmente una dirección de callback local (<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>, seleccionando automáticamente según la situación de escucha IPv4/IPv6 del sistema), esperará a que el navegador regrese con <code>code</code> y luego intercambiará por token. (implementación en <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>)</p><p><strong>refresh_token</strong>: una credencial que &quot;puede usarse a largo plazo para actualizar access_token&quot;. Al agregar una cuenta en este proyecto, se usará primero para obtener access_token, luego obtener el correo real de Google e ignorar el email que ingreses en el frontend. (implementación en <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>)</p></div><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>&quot;Agregar cuenta&quot; en Antigravity Tools, en última instancia, se trata de obtener un <code>refresh_token</code> disponible y escribir la información de la cuenta en el pool de cuentas local.</p><ul><li><strong>Vía OAuth</strong>: la aplicación te ayuda a generar el enlace de autorización y escuchar el callback local; después de que la autorización se complete, intercambia automáticamente el token y guarda la cuenta (ver <code>prepare_oauth_url</code>, <code>start_oauth_login</code>, <code>complete_oauth_login</code>)</li><li><strong>Vía Refresh Token</strong>: pegas directamente el <code>refresh_token</code>, la aplicación lo usará para actualizar el access_token y obtener el correo real de Google para guardarlo en disco (ver <code>add_account</code>)</li></ul><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-abrir-el-dialogo-agregar-cuenta" tabindex="-1">Paso 1: abrir el diálogo &quot;Agregar cuenta&quot; <a class="header-anchor" href="#paso-1-abrir-el-dialogo-agregar-cuenta" aria-label="Permalink to &quot;Paso 1: abrir el diálogo &quot;Agregar cuenta&quot;&quot;">​</a></h3><p><strong>Por qué</strong> Todas las entradas de adición están centralizadas en la página <code>Accounts</code>.</p><p>Operación: entra en la página <code>Accounts</code> y haz clic en el botón <strong>Add Account</strong> a la derecha (componente: <code>AddAccountDialog</code>).</p><p><strong>Deberías ver</strong>: aparece un diálogo con 3 pestañas: <code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code> (ver <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code>).</p><h3 id="paso-2-prioriza-oauth-para-autorizar-con-un-clic-recomendado" tabindex="-1">Paso 2: prioriza OAuth para autorizar con un clic (recomendado) <a class="header-anchor" href="#paso-2-prioriza-oauth-para-autorizar-con-un-clic-recomendado" aria-label="Permalink to &quot;Paso 2: prioriza OAuth para autorizar con un clic (recomendado)&quot;">​</a></h3><p><strong>Por qué</strong> Esta es la ruta predeterminada recomendada por el producto: deja que la aplicación genere el enlace de autorización, abra automáticamente el navegador y complete el guardado automáticamente cuando regrese el callback.</p><ol><li>Cambia a la pestaña <code>OAuth</code>.</li><li>Primero copia el enlace de autorización: al abrir el diálogo, llamará automáticamente a <code>prepare_oauth_url</code> para pregenerar la URL (llamada del frontend en <code>AddAccountDialog.tsx:111-125</code>; generación y escucha del backend en <code>oauth_server.rs</code>).</li><li>Haz clic en <strong>Start OAuth</strong> (correspondiente al frontend <code>startOAuthLogin()</code> / backend <code>start_oauth_login</code>), para que la aplicación abra el navegador predeterminado y comience a esperar el callback.</li></ol><p><strong>Deberías ver</strong>:</p><ul><li>Aparece un enlace de autorización copiable en el diálogo (nombre del evento: <code>oauth-url-generated</code>)</li><li>El navegador abre la página de autorización de Google; después de autorizar, redirigirá a una dirección local y mostrará &quot;Authorization Successful!&quot; (<code>oauth_success_html()</code>)</li></ul><h3 id="paso-3-cuando-oauth-no-se-completa-automaticamente-usa-finish-oauth-para-completar-manualmente" tabindex="-1">Paso 3: cuando OAuth no se completa automáticamente, usa &quot;Finish OAuth&quot; para completar manualmente <a class="header-anchor" href="#paso-3-cuando-oauth-no-se-completa-automaticamente-usa-finish-oauth-para-completar-manualmente" aria-label="Permalink to &quot;Paso 3: cuando OAuth no se completa automáticamente, usa &quot;Finish OAuth&quot; para completar manualmente&quot;">​</a></h3><p><strong>Por qué</strong> El proceso de OAuth tiene dos partes: el navegador obtiene <code>code</code> mediante autorización, luego la aplicación usa <code>code</code> para intercambiar token. Incluso si no hiciste clic en &quot;Start OAuth&quot;, mientras abras manualmente el enlace de autorización y completes el callback, el diálogo intentará completar automáticamente; si no se completa con éxito, puedes hacerlo manualmente una vez.</p><ol><li>Si &quot;copiaste el enlace y lo abriste en tu propio navegador&quot; (en lugar del navegador predeterminado), después de que el callback de autorización regrese, la aplicación recibirá el evento <code>oauth-callback-received</code> y llamará automáticamente a <code>completeOAuthLogin()</code> (ver <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code>).</li><li>Si no ves que se complete automáticamente, haz clic en <strong>Finish OAuth</strong> en el diálogo (correspondiente al backend <code>complete_oauth_login</code>).</li></ol><p><strong>Deberías ver</strong>: el diálogo muestra éxito y se cierra automáticamente; aparece una nueva cuenta en la lista <code>Accounts</code>.</p><div class="tip custom-block"><p class="custom-block-title">Truco: cuando el callback no puede conectar, prioriza copiar el enlace</p><p>El backend intentará escuchar tanto IPv6 <code>::1</code> como IPv4 <code>127.0.0.1</code> al mismo tiempo, y seleccionará <code>localhost/127.0.0.1/[::1]</code> como dirección de callback según la situación de escucha, principalmente para evitar fallos de conexión causados por &quot;el navegador resuelve localhost a IPv6&quot;. (ver <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>)</p></div><h3 id="paso-4-agregar-manualmente-con-refresh-token-admite-por-lotes" tabindex="-1">Paso 4: agregar manualmente con Refresh Token (admite por lotes) <a class="header-anchor" href="#paso-4-agregar-manualmente-con-refresh-token-admite-por-lotes" aria-label="Permalink to &quot;Paso 4: agregar manualmente con Refresh Token (admite por lotes)&quot;">​</a></h3><p><strong>Por qué</strong> Cuando no puedes obtener <code>refresh_token</code> (o prefieres &quot;activo portable&quot;), agregar directamente con Refresh Token es más controlable.</p><ol><li>Cambia a la pestaña <code>Refresh Token</code>.</li><li>Pega el <code>refresh_token</code> en el cuadro de texto.</li></ol><p>Formas de entrada admitidas (el frontend analizará y agregará por lotes):</p><table tabindex="0"><thead><tr><th>Tipo de entrada</th><th>Ejemplo</th><th>Lógica de análisis</th></tr></thead><tbody><tr><td>Texto de token puro</td><td><code>1//abc...</code></td><td>Extracción por expresión regular: <code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code> (ver <code>AddAccountDialog.tsx:213-220</code>)</td></tr><tr><td>Insertado en un texto grande</td><td>texto de registro/exportación contiene múltiples <code>1//...</code></td><td>Extracción por lotes por regex y desduplicación (ver <code>AddAccountDialog.tsx:213-224</code>)</td></tr><tr><td>Array JSON</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>Analizar el array y tomar <code>item.refresh_token</code> (ver <code>AddAccountDialog.tsx:198-207</code>)</td></tr></tbody></table><p>Después de hacer clic en <strong>Confirm</strong>, el diálogo llamará a <code>onAdd(&quot;&quot;, token)</code> uno por uno según la cantidad de tokens (ver <code>AddAccountDialog.tsx:231-248</code>), que finalmente llegara al backend <code>add_account</code>.</p><p><strong>Deberías ver</strong>:</p><ul><li>El diálogo muestra el progreso por lotes (por ejemplo <code>1/5</code>)</li><li>Después del éxito, aparece una nueva cuenta en la lista <code>Accounts</code></li></ul><h3 id="paso-5-confirmar-el-pool-de-cuentas-esta-disponible" tabindex="-1">Paso 5: confirmar &quot;el pool de cuentas está disponible&quot; <a class="header-anchor" href="#paso-5-confirmar-el-pool-de-cuentas-esta-disponible" aria-label="Permalink to &quot;Paso 5: confirmar &quot;el pool de cuentas está disponible&quot;&quot;">​</a></h3><p><strong>Por qué</strong> Agregado exitosamente no significa &quot;puedes usarlo de forma estable inmediatamente&quot;. El backend activará automáticamente un &quot;refresh de cuota&quot; después de agregar, y cuando Proxy se esté ejecutando, intentará recargar el token pool para que los cambios surtan efecto de inmediato.</p><p>Puedes confirmar con estas 2 señales:</p><ol><li>La cuenta aparece en la lista y muestra el correo (el correo proviene del backend <code>get_user_info</code>, no del email que ingresaste).</li><li>La información de cuota/suscripción de la cuenta comienza a actualizarse (el backend llamará automáticamente a <code>internal_refresh_account_quota</code>).</li></ol><p><strong>Deberías ver</strong>: después de agregar, no necesitas hacer clic manualmente en actualizar, la cuenta comenzará a mostrar información de cuota (el éxito se basa en la visualización real de la interfaz).</p><h2 id="puntos-de-verificacion-✅" tabindex="-1">Puntos de verificación ✅ <a class="header-anchor" href="#puntos-de-verificacion-✅" aria-label="Permalink to &quot;Puntos de verificación ✅&quot;">​</a></h2><ul><li>Puedes ver el correo de la cuenta recién agregada en la lista de cuentas</li><li>No se queda en estado &quot;loading&quot; más tiempo del que puedas aceptar (después de que se complete el callback de OAuth, debería completarse rápidamente)</li><li>Si estás ejecutando Proxy, las cuentas recién agregadas pueden participar en la programación rápidamente (el backend intentará recargar)</li></ul><h2 id="advertencias-sobre-problemas-comunes" tabindex="-1">Advertencias sobre problemas comunes <a class="header-anchor" href="#advertencias-sobre-problemas-comunes" aria-label="Permalink to &quot;Advertencias sobre problemas comunes&quot;">​</a></h2><h3 id="_1-oauth-muestra-no-se-pudo-obtener-refresh-token" tabindex="-1">1) OAuth muestra &quot;No se pudo obtener Refresh Token&quot; <a class="header-anchor" href="#_1-oauth-muestra-no-se-pudo-obtener-refresh-token" aria-label="Permalink to &quot;1) OAuth muestra &quot;No se pudo obtener Refresh Token&quot;&quot;">​</a></h3><p>El backend en <code>start_oauth_login/complete_oauth_login</code> verificará explícitamente si existe <code>refresh_token</code>; si no existe, devolverá un mensaje de error con solución (ver <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code>).</p><p>Sigue el método de manejo sugerido por el código fuente:</p><ol><li>Abre <code>https://myaccount.google.com/permissions</code></li><li>Revoca el acceso de <strong>Antigravity Tools</strong></li><li>Vuelve a la aplicación y sigue OAuth nuevamente</li></ol><blockquote><p>También puedes cambiar directamente a la vía Refresh Token de esta lección.</p></blockquote><h3 id="_2-el-navegador-muestra-localhost-refused-to-connect" tabindex="-1">2) El navegador muestra <code>localhost refused to connect</code> <a class="header-anchor" href="#_2-el-navegador-muestra-localhost-refused-to-connect" aria-label="Permalink to &quot;2) El navegador muestra `localhost refused to connect`&quot;">​</a></h3><p>El callback de OAuth necesita que el navegador solicite la dirección de callback local. Para reducir la tasa de fallos, el backend:</p><ul><li>Intentará escuchar <code>127.0.0.1</code> y <code>::1</code> al mismo tiempo</li><li>Solo usará <code>localhost</code> cuando ambos estén disponibles, de lo contrario forzará <code>127.0.0.1</code> o <code>[::1]</code></li></ul><p>La implementación correspondiente está en <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>.</p><h3 id="_3-cambiar-a-otra-pestana-cancelara-la-preparacion-de-oauth" tabindex="-1">3) Cambiar a otra pestaña cancelará la preparación de OAuth <a class="header-anchor" href="#_3-cambiar-a-otra-pestana-cancelara-la-preparacion-de-oauth" aria-label="Permalink to &quot;3) Cambiar a otra pestaña cancelará la preparación de OAuth&quot;">​</a></h3><p>Cuando el diálogo cambia de <code>OAuth</code> a otra pestaña, el frontend llamará a <code>cancelOAuthLogin()</code> y vaciará la URL (ver <code>AddAccountDialog.tsx:127-136</code>).</p><p>Si estás en medio de la autorización, no te apresures a cambiar de pestaña.</p><h3 id="_4-ejemplos-correctos-incorrectos-de-refresh-token" tabindex="-1">4) Ejemplos correctos/incorrectos de Refresh Token <a class="header-anchor" href="#_4-ejemplos-correctos-incorrectos-de-refresh-token" aria-label="Permalink to &quot;4) Ejemplos correctos/incorrectos de Refresh Token&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Ejemplo</th><th>¿Se reconoce?</th><th>Razón</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td>Cumple la regla de prefijo <code>1//</code> (ver <code>AddAccountDialog.tsx:215-219</code>)</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>No cumple la regla de extracción del frontend, se considerará entrada no válida</td></tr></tbody></table><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><ul><li>OAuth: adecuado para &quot;rápido&quot;, también admite copiar el enlace a tu navegador habitual y completar automáticamente/manualmente</li><li>Refresh Token: adecuado para &quot;estable&quot; y &quot;portable&quot;, admite extracción por lotes de <code>1//...</code> desde texto/JSON</li><li>Cuando no puedas obtener <code>refresh_token</code>, revoca la autorización según el mensaje de error y repite, o cambia directamente a Refresh Token</li></ul><h2 id="proximo-capitulo" tabindex="-1">Próximo capítulo <a class="header-anchor" href="#proximo-capitulo" aria-label="Permalink to &quot;Próximo capítulo&quot;">​</a></h2><p>En el próximo capítulo haremos algo más práctico: convertir el pool de cuentas en &quot;activo portable&quot;.</p><blockquote><p>Ve a aprender <strong><a href="/docs/opencodedocs/es/lbjlaq/Antigravity-Manager/start/backup-migrate/">Respaldo y migración de cuentas: importación/exportación, migración en caliente V1/DB</a></strong>.</p></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver las ubicaciones del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Página Accounts monta el diálogo de adición</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>Pregeneración de URL OAuth + finalización automática de eventos de callback</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L49-L125" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>49-125</td></tr><tr><td>Evento de callback OAuth activa <code>completeOAuthLogin()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Análisis por lotes y desduplicación de Refresh Token</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>Frontend llama a comandos Tauri (add/OAuth/cancel)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>Backend add_account: ignora email, usa refresh_token para obtener correo real y guardar</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>Backend OAuth: verifica ausencia de refresh_token y proporciona solución de revocación</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>Server de callback OAuth: escucha IPv4/IPv6 simultáneamente y selecciona redirect_uri</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Nombres de eventos clave</strong>:</p><ul><li><code>oauth-url-generated</code>: backend envía la URL OAuth al frontend después de generarla (ver <code>oauth_server.rs:250-252</code>)</li><li><code>oauth-callback-received</code>: backend notifica al frontend después de recibir el callback y analizar el code (ver <code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code>)</li></ul><p><strong>Comandos clave</strong>:</p><ul><li><code>prepare_oauth_url</code>: pregenera enlace de autorización e inicia escucha de callback (ver <code>src-tauri/src/commands/mod.rs:469-473</code>)</li><li><code>start_oauth_login</code>: abre el navegador predeterminado y espera el callback (ver <code>src-tauri/src/commands/mod.rs:339-401</code>)</li><li><code>complete_oauth_login</code>: no abre el navegador, solo espera el callback y completa el intercambio de token (ver <code>src-tauri/src/commands/mod.rs:405-467</code>)</li><li><code>add_account</code>: guarda la cuenta usando refresh_token (ver <code>src-tauri/src/commands/mod.rs:19-60</code>)</li></ul></details>',67)])])}const h=a(c,[["render",n]]);export{m as __pageData,h as default};
